import { DeferredTask } from "./DeferredTask.mjs";

const themeStorage = window.localStorage;

export const THEME_MODE_LIST = ["light", "dark"];

export const VARIANT_COLOR_LIST = [
  "red",
  "orange",
  "amber",
  "yellow",
  "lime",
  "green",
  "emerald",
  "teal",
  "cyan",
  "sky",
  "blue",
  "indigo",
  "violet",
  "purple",
  "fuchsia",
  "pink",
  "rose",
  "slate",
  "gray",
  "zinc",
  "neutral",
  "stone",
  "taupe",
  "mauve",
  "mist",
  "olive",
];

export const VARIANTS = ["brand", "danger", "neutral", "success", "warning"];

export const NUMBERS = [50, 100, 200, 300, 400, 500, 600, 700, 800, 900, 950];

export const COLORS = [
  "red",
  "orange",
  "amber",
  "yellow",
  "lime",
  "green",
  "emerald",
  "teal",
  "cyan",
  "sky",
  "blue",
  "indigo",
  "violet",
  "purple",
  "fuchsia",
  "pink",
  "rose",
  "slate",
  "gray",
  "zinc",
  "neutral",
  "stone",
  "taupe",
  "mauve",
  "mist",
  "olive",
];

export const TAILWIND_COLORS = COLORS.flatMap((color) =>
  NUMBERS.map((number) => `--color-${color}-${number}`),
);

export const BACKGROUND_COLOR_LIST = ["niks-favorite", ...TAILWIND_COLORS];

export const COLOR_PALETTE_LIST = [
  "default",
  "bright",
  "shoelace",
  "rudimentary",
  "elegant",
  "mild",
  "natural",
  "anodized",
  "vogue",
];

function round(num, digits = 2) {
  if (num === null) {
    return null;
  }

  return (
    Math.round((num + Number.EPSILON) * Math.pow(10, digits)) /
    Math.pow(10, digits)
  );
}

export class Theme {
  #mode;
  #primaryColor;
  #backgroundColor;
  #colorPalette;
  #rounding;
  #spacing;
  #borderWidth;
  #initing;

  #brandColor;
  #dangerColor;
  #neutralColor;
  #successColor;
  #warningColor;

  constructor(theme) {
    this.#initing = true;
    this.domProperties = window.getComputedStyle(document.documentElement);
    this.mode = theme.mode;
    this.backgroundColor = theme.background_color;
    this.colorPalette = theme.color_palette;
    this.rounding = theme.rounding;
    this.spacing = theme.spacing;
    this.borderWidth = theme.border_width;

    for (let [variant, color] of Object.entries(theme).filter(([k, v]) =>
      VARIANTS.includes(k),
    )) {
      this.setVariantColor(variant, color);
    }

    this.#initing = false;
  }

  get mode() {
    return this.#mode;
  }

  get primaryColor() {
    return this.#primaryColor;
  }

  get backgroundColor() {
    return this.#backgroundColor;
  }

  get colorPalette() {
    return this.#colorPalette;
  }

  get rounding() {
    return (
      this.#rounding ??
      this.domProperties.getPropertyValue("--wa-border-radius-scale")
    );
  }

  get spacing() {
    return (
      this.#spacing ?? this.domProperties.getPropertyValue("--wa-space-scale")
    );
  }

  get borderWidth() {
    return (
      this.#borderWidth ??
      this.domProperties.getPropertyValue("--wa-border-width-scale")
    );
  }

  get paletteLinkEl() {
    return document.getElementById("palette");
  }

  set mode(mode) {
    if (!mode) {
      mode = themeStorage.getItem("theme.mode");
    }
    if (mode && mode === this.mode) {
      return;
    }

    if (THEME_MODE_LIST.includes(mode)) {
      this.#mode = mode;
    } else {
      this.#mode = "light";
    }

    themeStorage.setItem("mode", this.mode);

    // Set theme mode on document
    document.documentElement.classList.toggle("wa-dark", this.mode === "dark");
    document.documentElement.classList.toggle(
      "wa-light",
      this.mode === "light",
    );

    if (!this.#initing) {
      this.updateSettings({ mode: this.mode });
    }
  }

  /**
   * Sets the primary color
   */
  set primaryColor(primaryColor) {
    if (primaryColor === this.primaryColor) {
      return;
    }

    document.documentElement.classList.remove(`${this.primaryColor}-brand`);

    if (VARIANT_COLOR_LIST.includes(primaryColor)) {
      this.#primaryColor = primaryColor;
    } else {
      this.#primaryColor = null;
    }

    themeStorage.setItem("primaryColor", this.primaryColor);
    if (this.primaryColor) {
      document.documentElement.classList.add(`${this.primaryColor}-brand`);
    }

    if (!this.#initing) {
      this.updateSettings({ primary_color: this.primaryColor });
    }
  }

  setVariantColor(variant, value) {
    if (!VARIANT_COLOR_LIST.includes(value)) {
      value = null;
    }

    let removeColor = null;

    switch (variant) {
      case "brand": {
        if (this.#brandColor === value) {
          return;
        }

        removeColor = this.#brandColor;
        this.#brandColor = value;
        break;
      }
      case "danger": {
        if (this.#dangerColor === value) {
          return;
        }

        removeColor = this.#dangerColor;
        this.#dangerColor = value;
        break;
      }
      case "neutral": {
        if (this.#neutralColor === value) {
          return;
        }

        removeColor = this.#neutralColor;
        this.#neutralColor = value;
        break;
      }
      case "success": {
        if (this.#successColor === value) {
          return;
        }

        removeColor = this.#successColor;
        this.#successColor = value;
        break;
      }
      case "warning": {
        if (this.#warningColor === value) {
          return;
        }

        removeColor = this.#warningColor;
        this.#warningColor = value;
        break;
      }
      default: {
        return;
      }
    }

    themeStorage.setItem(`${variant}Color`, value);
    document.documentElement.classList.remove(`${removeColor}-${variant}`);
    if (value) {
      document.documentElement.classList.add(`${value}-${variant}`);
    }

    if (!this.#initing) {
      let settingsObject = {};
      settingsObject[variant] = value;
      this.updateSettings(settingsObject);
    }
  }

  getVariantColor(variant) {
    switch (variant) {
      case "brand": {
        return this.#brandColor;
      }
      case "danger": {
        return this.#dangerColor;
      }
      case "neutral": {
        return this.#neutralColor;
      }
      case "success": {
        return this.#successColor;
      }
      case "warning": {
        return this.#warningColor;
      }
    }

    return null;
  }

  /**
   * Sets the background color
   */
  set backgroundColor(backgroundColor) {
    if (backgroundColor === this.backgroundColor) {
      return;
    }

    if (BACKGROUND_COLOR_LIST.includes(backgroundColor)) {
      this.#backgroundColor = backgroundColor;
    } else {
      this.#backgroundColor = null;
    }

    themeStorage.setItem("backgroundColor", this.backgroundColor);
    if (this.backgroundColor) {
      document.documentElement.style.setProperty(
        "--nb-background-color",
        `var(${this.backgroundColor}`,
      );
    } else {
      document.documentElement.style.removeProperty("--nb-background-color");
    }

    if (!this.#initing) {
      this.updateSettings({ background_color: this.backgroundColor });
    }
  }

  /**
   * Sets the color palette
   */
  set colorPalette(colorPalette) {
    if (colorPalette === this.colorPalette) {
      return;
    }

    document.documentElement.classList.remove(
      `wa-palette-${this.colorPalette}`,
    );

    if (COLOR_PALETTE_LIST.includes(colorPalette)) {
      this.#colorPalette = colorPalette;
    } else {
      this.#colorPalette = null;
    }

    themeStorage.setItem("colorPalette", this.colorPalette);

    if (this.colorPalette) {
      document.documentElement.classList.add(`wa-palette-${this.colorPalette}`);
    }

    this.paletteLinkEl.href =
      CSS_FILE_MAP[this.colorPalette + ".palette"] ?? "";

    if (!this.#initing) {
      this.updateSettings({ color_palette: this.colorPalette });
    }
  }

  set rounding(rounding) {
    rounding = rounding === null ? null : Number(rounding);
    if (isNaN(rounding) || rounding === this.#rounding) {
      return;
    }

    rounding = round(rounding, 1);

    document.documentElement.style.removeProperty("--wa-border-radius-scale");
    if (rounding >= 0 && rounding <= 4) {
      this.#rounding = rounding;
    } else {
      this.#rounding = null;
    }

    if (this.#rounding !== null) {
      document.documentElement.style.setProperty(
        "--wa-border-radius-scale",
        this.#rounding,
      );
    }

    if (!this.#initing) {
      this.updateSettings({ rounding: this.#rounding });
    }
  }

  set spacing(spacing) {
    spacing = spacing === null ? null : Number(spacing);
    if (isNaN(spacing) || spacing === this.#spacing) {
      return;
    }

    spacing = round(spacing, 4);

    document.documentElement.style.removeProperty("--wa-space-scale");
    if (spacing >= 0.5 && spacing <= 2) {
      this.#spacing = spacing;
    } else {
      this.#spacing = null;
    }

    if (this.#spacing !== null) {
      document.documentElement.style.setProperty(
        "--wa-space-scale",
        this.#spacing,
      );
    }

    if (!this.#initing) {
      this.updateSettings({ spacing: this.#spacing });
    }
  }

  set borderWidth(borderWidth) {
    borderWidth = borderWidth === null ? null : Number(borderWidth);
    if (isNaN(borderWidth) || borderWidth === this.#borderWidth) {
      return;
    }

    borderWidth = round(borderWidth, 1);

    document.documentElement.style.removeProperty("--wa-border-width-scale");
    if (borderWidth >= 0.5 && borderWidth <= 4) {
      this.#borderWidth = borderWidth;
    } else {
      this.#borderWidth = null;
    }

    if (this.#borderWidth !== null) {
      document.documentElement.style.setProperty(
        "--wa-border-width-scale",
        this.#borderWidth,
      );
    }

    if (!this.#initing) {
      this.updateSettings({ border_width: this.#borderWidth });
    }
  }

  updateSettings(args) {
    if (!CURRENT_USER?.id) {
      return;
    }

    if (!this.updateTask) {
      this.updateTask = new DeferredTask(
        (callbackArgs) => {
          try {
            Sentry.metrics.count("updateSettings", 1, {
              attributes: callbackArgs,
            });
          } catch {}
          return fetch(UPDATE_USER_SETTINGS, {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
            },
            body: JSON.stringify(callbackArgs),
            keepalive: true,
          });
        },
        1000,
        { finalizeBeforeUnload: true },
      );
    }
    this.updateTask.arm(args);
  }

  makeDefault() {
    this.mode = "light";
  }

  migrateTheme(themeMode) {
    this.mode = themeMode;
  }
}
